import json, collections, statistics, math
BASE='/source/phase_segment_12_phase_0/results'

def load(fn):
    rows=[]
    with open(f'{BASE}/{fn}') as f:
        for line in f:
            r=json.loads(line)
            if r.get('_meta'): continue
            rows.append(r)
    return rows

def eff(r):
    # robust for sumprod/mul, first-int otherwise
    return int(r['correct_robust'] if r['family'] in ('sumprod','multiplication') else r['correct'])

def boost(rows,k,size,labels):
    d=collections.defaultdict(dict)
    for r in rows:
