cands=[]
for inst in range(1000):
  for lab in [1,2,3,4]:
    keys=[(inst,lab,0),(inst,lab,100)]
    if all(k in A for k in keys) and all(k in B for k in keys):
      a0,a1=A[keys[0]],A[keys[1]]; b0,b1=B[keys[0]],B[keys[1]]
      if (not eff(a0)) and (not eff(a1)) and eff(b1):
        cands.append((inst,lab,a0,a1,b0,b1))
        if len(cands)>=5: break
  if len(cands)>=5: break
print('cands',len(cands))
for inst,lab,a0,a1,b0,b1 in cands[:3]:
    print('\ninst',inst,'label',lab,'question',a1['revealed_question'],'truth',a1['truth'])
    for name,r in [('after no filler',a0),('after filler',a1),('before no filler',b0),('before filler',b1)]:
