import json, collections
BASE='/source/phase_segment_12_phase_0'
def load(fn):
 rows=[]
 for line in open(f'{BASE}/results/{fn}'):
  r=json.loads(line)
  if not r.get('_meta'): rows.append(r)
 return rows
def eff(r): return int(r['correct_robust'] if r['family'] in ('sumprod','multiplication') else r['correct'])
def acc(rows,k,size,label=None):
 vals=[eff(r) for r in rows if r['k']==k and r['filler_items']==size and (label is None or r['reveal_label']==label)]
 return sum(vals)/len(vals)*100, len(vals)
# structure matched k=1
r1=load('seg7_sumprod_k1_after.jsonl')
print('k1 n0',acc(r1,1,0),'n200(size100)',acc(r1,1,100),'boost',acc(r1,1,100)[0]-acc(r1,1,0)[0])
# headline Q1 after
ra=load('seg7_sumprod_k8_after.jsonl'); rb=load('seg7_sumprod_k8_before.jsonl')
print('after Q1 n0',acc(ra,8,0,1),'n200',acc(ra,8,100,1),'boost',acc(ra,8,100,1)[0]-acc(ra,8,0,1)[0])
print('before Q1 n0',acc(rb,8,0,1),'n200',acc(rb,8,100,1),'boost',acc(rb,8,100,1)[0]-acc(rb,8,0,1)[0])
# early pool after k8
for rows,name in [(ra,'after'),(rb,'before')]:
 vals0=[]; vals1=[]
 for r in rows:
  if r['k']==8 and r['reveal_label'] in [1,2,3,4]:
   if r['filler_items']==0: vals0.append(eff(r))
   if r['filler_items']==100: vals1.append(eff(r))
 print(name,'early n0',sum(vals0)/len(vals0)*100,'n200',sum(vals1)/len(vals1)*100,'boost', (sum(vals1)/len(vals1)-sum(vals0)/len(vals0))*100)
# example inst9 label1
A={(r['inst'],r['reveal_label'],r['filler_items']):r for r in ra}; B={(r['inst'],r['reveal_label'],r['filler_items']):r for r in rb}
for name,r in [('after0',A[(9,1,0)]),('after100',A[(9,1,100)]),('before0',B[(9,1,0)]),('before100',B[(9,1,100)])]: print(name,r['revealed_question'],r['truth'],r['parsed_robust'],eff(r),repr(r['raw_output']))
